function countVowelsConsonants(str) {
  const vowels = new Set('aeiouAEIOU');
  let vowelsCount = 0;
  for (const char of str) {
    if (vowels.has(char)) vowelsCount++;
  }
  return {
    vowels: vowelsCount,
    consonants: str.length - vowelsCount
  };
}

function countRegex(str) {
  const vowels = (str.match(/[aeiou]/gi) || []).length;
  return {
    vowels,
    consonants: str.length - vowels
  };
}

function countTyped(str) {
  const vowelCodes = new Set([97,101,105,111,117,65,69,73,79,85]);
  let count = 0;
  for (const char of str) {
    if (vowelCodes.has(char.charCodeAt(0))) count++;
  }
  return { vowels: count, consonants: str.length - count };
}
